  ('diplomatic-9e854390-moex-00166', 'diplomatic-9e854390', 'diplomatic-9e854390-moex-112-d35177eb', 'sub-diplomatic-9e854390-02', NULL, 'essay', '雲河公司在南亞銀行設立支票存款帳戶。X1 年 10 月底公司帳上銀行存
款餘額為$10,500，並收到銀行寄來對帳單，業經核對資料得知：
㉑委託銀行代收之票據$3,000，銀行已代為收取，但公司尚未入帳。
㉒客戶開立支票$2,500 以支付貨款，經公司存入銀行後因客戶存款不足
而致退票。
㉓銀行收取 10月份各項服務手續費共計$120，公司尚未入帳。
㉔ 10 月底公司存入$1,200，銀行尚未入帳。
㉕公司共開立支票$20,250，銀行截至 10月底僅兌現$19,450。
㉖銀行漏列公司於 10 月 20日存入之存款$500。
試作：
X1 年 10 月 31 日正確之銀行存款帳戶餘額及銀行對帳單之存款餘額
各為多少？（6分）（需列示計算過程，否則不予計分）
雲河公司應補作之分錄。（9 分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:22:30+00:00", "source_pdf_sha1": "873fbf1da003", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "112150", "c": "201", "s": "1305", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "會計學概要", "year": "112", "exam_name": "112年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": "二", "answer_corrected": false, "flags": [], "civil_slug": "diplomatic", "civil_category": "外交行政人員-行政組"}'::jsonb, NULL),
  ('diplomatic-9e854390-moex-00167', 'diplomatic-9e854390', 'diplomatic-9e854390-moex-112-d35177eb', 'sub-diplomatic-9e854390-02', NULL, 'essay', '安雅公司在X1年初以$2,000,000購得一棟大樓，並支付代書費$120,000、
過戶登記費$30,000 及 X1 年之火險保費$40,000。安雅公司擬將該大樓
出租，預估使用年限為 25年，殘值$300,000。X1年底及 X2 年底該大樓
之公允價值分別為$2,200,000及$1,900,000。若該大樓為投資性不動產，
試作：
安雅公司 X1 年初應認列投資性不動產成本為多少？若安雅公司採成
本模式，作 X1年底之調整分錄。（6分）
若安雅公司採公允價值模式，作 X1 年及 X2 年底之調整分錄。（6 分）
若不考慮所得稅，公允價值模式之 X2 年淨利較成本模式之 X2 年淨
利高（或低）多少？（3分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:22:30+00:00", "source_pdf_sha1": "873fbf1da003", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "112150", "c": "201", "s": "1305", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "會計學概要", "year": "112", "exam_name": "112年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": "三", "answer_corrected": false, "flags": [], "civil_slug": "diplomatic", "civil_category": "外交行政人員-行政組"}'::jsonb, NULL),
  ('diplomatic-9e854390-moex-00168', 'diplomatic-9e854390', 'diplomatic-9e854390-moex-112-d35177eb', 'sub-diplomatic-9e854390-02', NULL, 'single_choice', '關於財務報表之敘述，下列何者錯誤？', '["資產負債表報導某一公司擁有的資源，及那些人對這些資源有請求權", "綜合損益總額包括損益及其他綜合損益", "重分類調整係指當期或以前期間分類錯誤而進行調整之金額", "權益變動表的目的之一，在提供企業與業主（以業主之身分）之交易資訊"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:22:30+00:00", "source_pdf_sha1": "873fbf1da003", "answer_pdf_sha1": "eb4dccfb0e24", "source_family": "moex-gov-tw", "moex": {"exam_code": "112150", "c": "201", "s": "1305", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學概要", "year": "112", "exam_name": "112年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 1, "answer_corrected": false, "flags": [], "civil_slug": "diplomatic", "civil_category": "外交行政人員-行政組"}'::jsonb, NULL),
  ('diplomatic-9e854390-moex-00169', 'diplomatic-9e854390', 'diplomatic-9e854390-moex-112-d35177eb', 'sub-diplomatic-9e854390-02', NULL, 'single_choice', '甲公司的會計人員在編製X3年12月31日之銀行調節表，收到銀行對帳單列示之X3年12月31 日之銀行帳戶餘額為$38,800，且銀行通知手續費$300、託收票據收現$5,800以及客戶存款不足支 票退票金額為$2,680。另外，公司帳列銀行存款餘額為$39,800；X3年12月31日之流通在外支票 金額為$7,000；編號為101的支票，銀行端已兌付之金額為$6,800，甲公司會計人員之會計記錄誤 記為$8,600。則銀行調節表中應包含之在途存款金額為：', '["$1,020", "$6,820", "$12,620", "$15,300"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:22:30+00:00", "source_pdf_sha1": "873fbf1da003", "answer_pdf_sha1": "eb4dccfb0e24", "source_family": "moex-gov-tw", "moex": {"exam_code": "112150", "c": "201", "s": "1305", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學概要", "year": "112", "exam_name": "112年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 2, "answer_corrected": false, "flags": [], "civil_slug": "diplomatic", "civil_category": "外交行政人員-行政組"}'::jsonb, NULL),
  ('diplomatic-9e854390-moex-00170', 'diplomatic-9e854390', 'diplomatic-9e854390-moex-112-d35177eb', 'sub-diplomatic-9e854390-02', NULL, 'single_choice', '甲公司係採用帳齡分析法估計預期信用減損損失，X8年12月31日應收帳款帳齡分析資料如下： 帳齡 借方餘額 損失比率 30天以下 $489,000 0.5% 31-90天 201,000 2% 91-180天 106,000 5% 181-360天 48,500 20% 361天以上 27,500 60% $872,000 X8年5月12日曾將確認無法收回之應收帳款$35,680沖銷；X8年12月31日調整前備抵損失為 借餘$970。甲公司X8年度應認列之預期信用減損損失為何？', '["$38,935", "$37,965", "$36,995", "$36,935"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:22:30+00:00", "source_pdf_sha1": "873fbf1da003", "answer_pdf_sha1": "eb4dccfb0e24", "source_family": "moex-gov-tw", "moex": {"exam_code": "112150", "c": "201", "s": "1305", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學概要", "year": "112", "exam_name": "112年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 3, "answer_corrected": false, "flags": [], "civil_slug": "diplomatic", "civil_category": "外交行政人員-行政組"}'::jsonb, NULL),
  ('diplomatic-9e854390-moex-00171', 'diplomatic-9e854390', 'diplomatic-9e854390-moex-112-d35177eb', 'sub-diplomatic-9e854390-02', NULL, 'single_choice', '甲公司X1年度與X2年度的淨利皆為$300,000，若會計師發現X1年底存貨低估$15,000，X2年 底存貨高估$15,000，則甲公司X1年度及X2年度正確的淨利應分別為何？（不考慮所得稅）', '["$285,000，$270,000", "$285,000，$330,000", "$315,000，$270,000", "$300,000，$300,000"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:22:30+00:00", "source_pdf_sha1": "873fbf1da003", "answer_pdf_sha1": "eb4dccfb0e24", "source_family": "moex-gov-tw", "moex": {"exam_code": "112150", "c": "201", "s": "1305", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學概要", "year": "112", "exam_name": "112年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 4, "answer_corrected": false, "flags": [], "civil_slug": "diplomatic", "civil_category": "外交行政人員-行政組"}'::jsonb, NULL),
  ('diplomatic-9e854390-moex-00172', 'diplomatic-9e854390', 'diplomatic-9e854390-moex-112-d35177eb', 'sub-diplomatic-9e854390-02', NULL, 'single_choice', '甲公司承造一橋樑工程，合約價格$600,000，工程於X1年開工，X2年完工，相關資料如下： X1年度 X2年度 當年度已發生成本 $300,000 $120,000 估計完工前尚需投入之成本 $150,000 若甲公司採用完工百分比法認列收入（以至今完工已發生合約成本占總合約成本比例衡量完成程 度），則X2年應認列的工程利益為：（不考慮所得稅影響數）', '["$120,000", "$0", "$100,000", "$80,000"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:22:30+00:00", "source_pdf_sha1": "873fbf1da003", "answer_pdf_sha1": "eb4dccfb0e24", "source_family": "moex-gov-tw", "moex": {"exam_code": "112150", "c": "201", "s": "1305", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學概要", "year": "112", "exam_name": "112年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 5, "answer_corrected": false, "flags": [], "civil_slug": "diplomatic", "civil_category": "外交行政人員-行政組"}'::jsonb, NULL),
  ('diplomatic-9e854390-moex-00173', 'diplomatic-9e854390', 'diplomatic-9e854390-moex-112-d35177eb', 'sub-diplomatic-9e854390-02', NULL, 'single_choice', '甲公司於X1年7月1日支付$210,834取得面額$200,000、票面利率8%之公司債，每年6月30 日及12月31日付息，並分類為按攤銷後成本衡量之金融資產。甲公司X1年12月31日認列利 息收入$6,325，該債券投資之有效利率與X1年底帳面金額分別為何？', '["3%、$210,834", "3%、$209,159", "6%、$210,834", "6%、$209,159"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:22:30+00:00", "source_pdf_sha1": "873fbf1da003", "answer_pdf_sha1": "eb4dccfb0e24", "source_family": "moex-gov-tw", "moex": {"exam_code": "112150", "c": "201", "s": "1305", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學概要", "year": "112", "exam_name": "112年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 6, "answer_corrected": false, "flags": [], "civil_slug": "diplomatic", "civil_category": "外交行政人員-行政組"}'::jsonb, NULL),
  ('diplomatic-9e854390-moex-00174', 'diplomatic-9e854390', 'diplomatic-9e854390-moex-112-d35177eb', 'sub-diplomatic-9e854390-02', NULL, 'single_choice', '甲公司於X8年1月1日以每股$10價格，取得乙公司30,000股流通在外普通股之40%股權，並 具有重大影響力。X8年6月15日乙公司宣布並發放普通股現金股利$60,000。X8年12月31日 乙公司報導當年度淨利為$90,000，該年應發放給累積特別股股利為$6,000。X8 年 12 月 31 日乙 公司普通股每股市價為$12。則甲公司X8年底，帳列採用權益法之投資（對乙公司之投資）餘額 應為何？', '["借餘$133,600", "借餘$132,000", "借餘$129,600", "借餘$96,000"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:22:30+00:00", "source_pdf_sha1": "873fbf1da003", "answer_pdf_sha1": "eb4dccfb0e24", "source_family": "moex-gov-tw", "moex": {"exam_code": "112150", "c": "201", "s": "1305", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學概要", "year": "112", "exam_name": "112年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 7, "answer_corrected": false, "flags": [], "civil_slug": "diplomatic", "civil_category": "外交行政人員-行政組"}'::jsonb, NULL),
  ('diplomatic-9e854390-moex-00175', 'diplomatic-9e854390', 'diplomatic-9e854390-moex-112-d35177eb', 'sub-diplomatic-9e854390-02', NULL, 'single_choice', '內部產生之無形資產分為研究階段與發展階段，下列何者不屬於發展階段的活動？', '["生產或使用前之原型或模式之設計、建造及測試", "涉及新技術之工具、夾具、模具及印模之設計", "未達經濟規模可行性以供商業化量產之試驗工廠，其設計、建造與作業", "對於全新或改良之材料、器械、產品、流程、系統或服務可能替代方案之草擬、設計、評估及 最終選定"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:22:30+00:00", "source_pdf_sha1": "873fbf1da003", "answer_pdf_sha1": "eb4dccfb0e24", "source_family": "moex-gov-tw", "moex": {"exam_code": "112150", "c": "201", "s": "1305", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學概要", "year": "112", "exam_name": "112年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 8, "answer_corrected": false, "flags": [], "civil_slug": "diplomatic", "civil_category": "外交行政人員-行政組"}'::jsonb, NULL)
